const fs = require('fs');

const filePath = $('Global Parameter Configuration').first().json.filePath;

// Đọc data cũ nếu có
let allData = [];
if (fs.existsSync(filePath)) {
  try {
    allData = JSON.parse(fs.readFileSync(filePath, 'utf8'));
  } catch(e) {
    allData = [];
  }
}

// Thêm data tỉnh hiện tại
const newData = $input.all()[0].json.data || [];
allData = allData.concat(newData);

// Ghi lại file
fs.writeFileSync(filePath, JSON.stringify(allData, null, 2), 'utf8');

// Trả về để loop tiếp tục
return newData.map(row => ({ json: row }));

// Tổng hợp kết quả đồng bộ để tạo alert message
const syncLogResult = $input.all()[0]?.json || {};
const recordsAffected = syncLogResult.records_affected || 0;
const syncTime = syncLogResult.synced_at || new Date().toISOString();
const runId = $('Global Parameter Configuration').item.json.runId;

const message = [
  '✅ *GOV-SYNC hoàn thành thành công*',
  `📅 Thời gian: ${new Date(syncTime).toLocaleString('vi-VN')}`,
  `🏛️ Đơn vị đã đồng bộ: ${recordsAffected} phường/xã`,
  `🔑 Run ID: ${runId}`,
  `🔗 Nguồn: danhmuchanhchinh.nso.gov.vn`,
  '',
  'Dữ liệu đã được cập nhật vào bảng mat.ward (admin_version=2) và ghi log vào ath.sync_log'
].join('\n');

return [{ json: { message, runId, recordsAffected } }];
